    VST1 [V3.S4], (R3)
    VST1 [V0.S4], (R4)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    ADD  $16, R4
    SUB  $4, R5
    B    adamax_loop4

adamax_done:
    RET

// func adagradStepFloat32NEONAsm(
